DELETE FROM TBL_COMMENT_LIKE
WHERE USER_ID = #{userId}
   OR COMMENT_ID IN (
    SELECT ID
    FROM TBL_COMMENT
             START WITH USER_ID = #{userId}
    OR POST_ID IN (SELECT ID FROM TBL_POST WHERE USER_ID = #{userId})
CONNECT BY PRIOR ID = COMMENT_ID
    )

DELETE FROM TBL_COMMENT_REPORT
WHERE USER_ID = #{userId}
   OR COMMENT_ID IN (
    SELECT ID
    FROM TBL_COMMENT
             START WITH USER_ID = #{userId}
    OR POST_ID IN (SELECT ID FROM TBL_POST WHERE USER_ID = #{userId})
CONNECT BY PRIOR ID = COMMENT_ID
    )

DELETE FROM TBL_POST_LIKE
WHERE USER_ID = #{userId}
   OR POST_ID IN (SELECT ID FROM TBL_POST WHERE USER_ID = #{userId})

DELETE FROM TBL_POST_REPORT
WHERE USER_ID = #{userId}
   OR POST_ID IN (SELECT ID FROM TBL_POST WHERE USER_ID = #{userId})

DELETE FROM TBL_FOLLOW
WHERE FOLLOWER_ID = #{userId}
   OR FOLLOWING_ID = #{userId}

DELETE FROM TBL_USER_BLOCK
WHERE BLOCKER_ID = #{userId}
   OR BLOCKING_ID = #{userId}

DELETE FROM TBL_REPORT_RESULT
WHERE REPORT_ID IN (
    SELECT ID
    FROM TBL_REPORT
    WHERE USER_ID = #{userId}
)

DELETE FROM TBL_USER_REPORT
WHERE USER_ID = #{userId}
OR REPORTING_USER_ID = #{userId}
